pipeline.evaluate:
(async () => {
  const limit = ${{ args.limit }} || 3;
  const NOTE_DETAIL_PAGE_URL = 'https://creator.xiaohongshu.com/statistics/note-detail';

  function buildNoteDetailUrl(noteId) {
    return noteId ? NOTE_DETAIL_PAGE_URL + '?noteId=' + encodeURIComponent(noteId) : '';
  }

  function formatPostTime(ts) {
    if (!ts) return '';
    const date = new Date(ts + 8 * 3600000);
    const pad = (v) => String(v).padStart(2, '0');
    return date.getUTCFullYear() + '年' + pad(date.getUTCMonth() + 1) + '月' + pad(date.getUTCDate()) + '日 ' + pad(date.getUTCHours()) + ':' + pad(date.getUTCMinutes());
  }

  // Step 1: Fetch note list via API
  const pageSize = Math.min(Math.max(limit, 10), 20);
  const notes = [];
  try {
    const resp = await fetch('/api/galaxy/creator/datacenter/note/analyze/list?type=0&page_size=' + pageSize + '&page_num=1', { credentials: 'include' });
    if (resp.ok) {
      const json = await resp.json();
      const items = json?.data?.note_infos ?? [];
      for (const item of items) {
        notes.push({
          id: item.id ?? '',
          title: item.title ?? '',
          date: formatPostTime(item.post_time),
          views: item.read_count ?? 0,
          likes: item.like_count ?? 0,
          collects: item.fav_count ?? 0,
          comments: item.comment_count ?? 0,
          url: buildNoteDetailUrl(item.id),
        });
      }
    }
  } catch {}

  if (!notes.length) {
    throw new Error('No notes found. Are you logged into creator.xiaohongshu.com?');
  }

  const toPercentString = (v) => v == null ? '' : v + '%';

  // Step 2: For each note, fetch detail data
  const results = [];
  for (let i = 0; i < Math.min(notes.length, limit); i++) {
    const note = notes[i];
    if (!note.id) {
      results.push({
        rank: i + 1,
        id: note.id,
        title: note.title,
        views: String(note.views),
        likes: String(note.likes),
        collects: String(note.collects),
        comments: String(note.comments),
        shares: '',
        avg_view_time: '',
        rise_fans: '',
        top_source: '',
        top_interest: '',
        url: note.url,
      });
      continue;
    }

    // Fetch detail APIs
    const detailRows = [];
    const API_ENDPOINTS = [
      '/api/galaxy/creator/datacenter/note/base',
      '/api/galaxy/creator/datacenter/note/audience/source/detail',
      '/api/galaxy/creator/datacenter/note/audience',
    ];
    const detailPayload = {};

    for (const ep of API_ENDPOINTS) {
      try {
        const resp = await fetch(ep + '?note_id=' + note.id, { credentials: 'include' });
        if (resp.ok) {
          const json = await resp.json();
          if (json.data) detailPayload[ep] = json.data;
        }
      } catch {}
    }

    // Extract key metrics from base data
    // The base API returns noteBase with hour/day trend data containing totals
    const baseData = detailPayload['/api/galaxy/creator/datacenter/note/base'];
    const audienceSource = detailPayload['/api/galaxy/creator/datacenter/note/audience'];
    const audienceDetail = detailPayload['/api/galaxy/creator/datacenter/note/audience/source/detail'];

    // Find top source
    let topSource = '';
    let topSourcePct = '';
    const sourceItems = audienceSource?.source ?? [];
    if (sourceItems.length > 0) {
      const sorted = [...sourceItems].sort((a, b) => (b.value_with_double ?? 0) - (a.value_with_double ?? 0));
      topSource = sorted[0]?.title ?? '';
      topSourcePct = toPercentString(sorted[0]?.value_with_double);
    }

    // Find top interest
    let topInterest = '';
    let topInterestPct = '';
    const interestItems = audienceDetail?.interest ?? [];
    if (interestItems.length > 0) {
      const sorted = [...interestItems].sort((a, b) => (b.value ?? 0) - (a.value ?? 0));
      topInterest = sorted[0]?.title ?? '';
      topInterestPct = toPercentString(sorted[0]?.value);
    }

    results.push({
      rank: i + 1,
      id: note.id,
      title: note.title,
      views: String(note.views),
      likes: String(note.likes),
      collects: String(note.collects),
      comments: String(note.comments),
      shares: '',
      avg_view_time: '',
      rise_fans: '',
      top_source: topSource,
      top_interest: topInterest,
      url: note.url,
    });
  }

  return results;
})()
